import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Navbar from '../components/shared/Navbar';
import { StarInput } from '../components/shared/StarRating';
import { bookingAPI, reviewAPI } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import { format } from 'date-fns';
import toast from 'react-hot-toast';

const STATUS_COLORS = {
  pending: 'warning', accepted: 'accent', in_progress: 'accent',
  completed: 'success', rejected: 'danger', cancelled: 'danger',
};
const STATUS_ICONS = { pending: '⏳', accepted: '✅', in_progress: '🔧', completed: '🎉', rejected: '❌', cancelled: '🚫' };

function ReviewModal({ booking, onClose, onDone }) {
  const [rating, setRating] = useState(0);
  const [comment, setComment] = useState('');
  const [tags, setTags] = useState([]);
  const [loading, setLoading] = useState(false);
  const TAGS = ['Professional', 'On time', 'Good work', 'Clean', 'Affordable', 'Friendly'];

  const submit = async () => {
    if (!rating) return toast.error('Please select a rating');
    setLoading(true);
    try {
      await reviewAPI.create({ bookingId: booking._id, rating, comment, tags });
      toast.success('Review submitted!');
      onDone();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <h3 style={{ fontWeight: 700, marginBottom: 20 }}>Rate Your Experience</h3>
        <div style={{ textAlign: 'center', marginBottom: 20 }}>
          <StarInput value={rating} onChange={setRating} />
          <p style={{ fontSize: 13, color: 'var(--text-muted)', marginTop: 6 }}>
            {rating === 5 ? '🎉 Excellent!' : rating === 4 ? '😊 Great!' : rating === 3 ? '😐 Average' : rating > 0 ? '😞 Poor' : 'Tap to rate'}
          </p>
        </div>
        <div className="form-group" style={{ marginBottom: 14 }}>
          <label className="form-label">Tags</label>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
            {TAGS.map(t => (
              <button key={t} type="button" className={`btn btn-sm ${tags.includes(t) ? 'btn-primary' : 'btn-ghost'}`}
                onClick={() => setTags(prev => prev.includes(t) ? prev.filter(x => x !== t) : [...prev, t])}>
                {t}
              </button>
            ))}
          </div>
        </div>
        <div className="form-group" style={{ marginBottom: 20 }}>
          <label className="form-label">Write a review (optional)</label>
          <textarea className="form-textarea" value={comment} onChange={e => setComment(e.target.value)} placeholder="How was your experience?" style={{ minHeight: 80 }} />
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <button className="btn btn-ghost" style={{ flex: 1 }} onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" style={{ flex: 2 }} onClick={submit} disabled={loading}>
            {loading ? 'Submitting...' : 'Submit Review'}
          </button>
        </div>
      </div>
    </div>
  );
}

export default function UserDashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('all');
  const [reviewBooking, setReviewBooking] = useState(null);

  const fetchBookings = () => {
    const params = {};
    if (activeTab !== 'all') params.status = activeTab;
    bookingAPI.getUserBookings(params)
      .then(r => setBookings(r.data.data))
      .catch(() => toast.error('Failed to load bookings'))
      .finally(() => setLoading(false));
  };

  useEffect(() => { fetchBookings(); }, [activeTab]);

  const TABS = [
    { key: 'all', label: 'All' },
    { key: 'pending', label: 'Pending' },
    { key: 'accepted', label: 'Accepted' },
    { key: 'in_progress', label: 'In Progress' },
    { key: 'completed', label: 'Completed' },
    { key: 'cancelled', label: 'Cancelled' },
  ];

  return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />
      {reviewBooking && (
        <ReviewModal booking={reviewBooking} onClose={() => setReviewBooking(null)} onDone={() => { setReviewBooking(null); fetchBookings(); }} />
      )}

      <div className="page-container" style={{ paddingTop: 32, paddingBottom: 48 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 28 }}>
          <div>
            <h1 style={{ fontSize: 26, fontWeight: 800 }}>My Dashboard</h1>
            <p style={{ color: 'var(--text-secondary)', fontSize: 14, marginTop: 4 }}>Welcome back, {user?.name} 👋</p>
          </div>
          <button className="btn btn-primary" onClick={() => navigate('/search')}>+ Book a Service</button>
        </div>

        {/* Tab Nav */}
        <div style={{ overflowX: 'auto', marginBottom: 24 }}>
          <div className="tab-nav" style={{ width: 'max-content' }}>
            {TABS.map(t => (
              <button key={t.key} className={`tab-btn ${activeTab === t.key ? 'active' : ''}`}
                onClick={() => setActiveTab(t.key)}>{t.label}</button>
            ))}
          </div>
        </div>

        {loading ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
            {[...Array(4)].map((_, i) => <div key={i} className="skeleton" style={{ height: 120 }} />)}
          </div>
        ) : bookings.length === 0 ? (
          <div className="empty-state card">
            <div className="empty-state-icon">📋</div>
            <h3>No bookings found</h3>
            <p>Book a service to get started</p>
            <button className="btn btn-primary" style={{ marginTop: 16 }} onClick={() => navigate('/search')}>Find Services</button>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
            {bookings.map(b => {
              const pUser = b.provider?.user || {};
              return (
                <div key={b._id} className="card card-hover" onClick={() => navigate(`/bookings/${b._id}`)}>
                  <div style={{ display: 'flex', gap: 16, alignItems: 'flex-start', flexWrap: 'wrap' }}>
                    <div style={{ width: 44, height: 44, borderRadius: '50%', background: 'var(--accent-dim)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--accent)', fontWeight: 700, fontSize: 14, flexShrink: 0 }}>
                      {pUser.name?.split(' ').map(n => n[0]).join('').slice(0, 2)}
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', flexWrap: 'wrap', gap: 8 }}>
                        <div>
                          <div style={{ fontWeight: 700 }}>{pUser.name}</div>
                          <div style={{ fontSize: 13, color: 'var(--text-secondary)' }}>{b.skillRequired} • {b.serviceCategory}</div>
                        </div>
                        <span className={`badge badge-${STATUS_COLORS[b.status]}`}>
                          {STATUS_ICONS[b.status]} {b.status.replace('_', ' ')}
                        </span>
                      </div>
                      <div style={{ display: 'flex', gap: 16, marginTop: 8, fontSize: 12, color: 'var(--text-muted)' }}>
                        <span>📅 {format(new Date(b.scheduledDate), 'EEE, d MMM yyyy')}</span>
                        <span>⏰ {b.scheduledTime}</span>
                        {b.finalPrice && <span>💰 ₹{b.finalPrice}</span>}
                      </div>
                    </div>
                    {b.status === 'completed' && !b.hasReview && (
                      <button className="btn btn-secondary btn-sm"
                        onClick={e => { e.stopPropagation(); setReviewBooking(b); }}>
                        ⭐ Rate
                      </button>
                    )}
                    {b.status === 'accepted' && b.paymentStatus === 'unpaid' && (
                      <button className="btn btn-primary btn-sm"
                        onClick={e => { e.stopPropagation(); navigate(`/bookings/${b._id}`); }}>
                        💳 Pay
                      </button>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}
